import type { Unit } from '@dynatrace-sdk/units';
/**
 * @public
 * @deprecated TimeseriesUnit is deprecated, use string | Unit instead.
 */
export type TimeseriesUnit = string | Unit | undefined;
/**
 * Datapoint representation of an item within a timeseries datapoints set
 * @public
 */
export interface TimeseriesDatapoint {
    /** Starting timestamp for the datapoint representation */
    start: Date;
    /** Ending timestamp for the datapoint representation */
    end?: Date;
    /** Timestamp that sits in the middle between start and end */
    center?: Date;
    /** Number value represented in the datapoint. This can either be the absolute value or a relative value  */
    value: number;
}
/**
 * One timeseries containing the datapoints
 * @public
 */
export interface Timeseries extends Record<string, unknown> {
    /** The datapoints recordset for this time series */
    datapoints: TimeseriesDatapoint[];
    /** The name or names in case of multiple dimensions for the time series */
    name: string | string[];
    /** Unit token for the value represented by the timeseries datapoints. Eg: 'kbit/s'  */
    unit?: TimeseriesUnit | Unit | string;
}
/**
 * Curve shape for line, band and area series
 * @public
 */
export type SeriesCurve = 'linear' | 'smooth';
